const chapters = [
  { id:'studieteknik', nr:'01', title:'Studieteknik för teknikelever', desc:'Lär dig använda The Science of Learning i matematik, fysik, kemi och teknik.', goals:['förklara hur aktiv återkallning, utspridd repetition och återkoppling stärker lärandet','planera ett kort studiepass med ett tydligt mål','använda metakognition före, under och efter en uppgift','välja en rimlig strategi när du fastnar'], sections:[['1. Lärande är något du gör','<p>Att känna igen en text är inte samma sak som att kunna den. Du behöver träna på att hämta fram kunskap ur minnet: förklara, rita, räkna, skriva eller använda ett begrepp utan att titta.</p><p><strong>Så gör du:</strong> Läs eller se en kort genomgång. Stäng sedan materialet. Skriv i två minuter allt du minns. Öppna materialet och rätta med en annan färg.</p>'],['2. Träna kort och återkom','<p>En lång kväll före ett prov kan kännas effektiv, men kunskap sitter bättre när du återkommer flera gånger. Gör hellre 20 minuter i dag, 15 minuter om två dagar och 10 minuter veckan efter.</p><p><strong>Repetitionsplan:</strong> dag 0 – förstå och prova; dag 2 – kort quiz utan stöd; dag 7 – en blandad uppgift; dag 21 – förklara för någon annan.</p>'],['3. Blanda uppgifter när grunden finns','<p>Om du bara gör tio nästan likadana ekvationer lär du dig ofta mönstret, men inte när metoden passar. Blanda därför procent, enheter och ekvationer när du har tränat varje del för sig.</p><p><strong>Fråga dig alltid:</strong> Vilken metod behöver jag här – och hur vet jag det?</p>'],['4. Minska belastningen när något är nytt','<p>När ett område är svårt: gör en sak i taget. Använd ett genomarbetat exempel, markera vilka värden som är givna och skriv ut enheter. Först därefter försöker du lösa en liknande uppgift själv.</p><p><strong>Fastna inte ensam:</strong> jämför med ett exempel, identifiera första oklara steget och formulera en konkret fråga.</p>'],['5. Använd fel som information','<p>Rättning är inte slutet på arbetet. Skriv varför svaret blev fel: missförstod jag frågan, saknade jag en metod, tappade jag en enhet eller gjorde jag ett räknefel?</p><p><strong>Gör sedan en ny, liknande uppgift.</strong> Det är det nya försöket efter återkopplingen som visar att du har lärt dig.</p>'],['6. Praktisk metakognition','<p><strong>Före:</strong> Vad kan jag redan? Vad är mitt mål? Vilken strategi börjar jag med?</p><p><strong>Under:</strong> Kan jag förklara steget? Vad är oklart? Behöver jag byta strategi eller be om hjälp?</p><p><strong>Efter:</strong> Vad fungerade? Vilket fel gjorde jag? När ska jag repetera nästa gång?</p>'],['Övning: min 25-minuterscykel','<ol><li><strong>2 min:</strong> Skriv ett konkret mål: “Jag kan omvandla mellan procent och decimalform.”</li><li><strong>8 min:</strong> Läs ett kort exempel och markera de viktigaste stegen.</li><li><strong>8 min:</strong> Lös två uppgifter utan att titta på exemplet.</li><li><strong>4 min:</strong> Rätta och skriv en mening om ett fel eller en osäkerhet.</li><li><strong>3 min:</strong> Bestäm exakt när du repeterar.</li></ol>']], example:'Du har just läst om Ohms lag. Täck över formeln och skriv: 1) vad ström, spänning och resistans betyder, 2) vilken enhet varje storhet har och 3) ett eget exempel på en enkel krets. Öppna sedan materialet, rätta och markera en sak att repetera om två dagar.', quiz:[['Vilken aktivitet tränar minnet mest aktivt?',['Läsa samma sida en gång till','Förklara innehållet utan att titta','Markera allt som verkar viktigt'],1,'Att försöka hämta fram kunskap ur minnet gör det lättare att komma ihåg senare.'],['När är en bra första repetition efter att du har lärt dig något nytt?',['Efter några dagar','Först kvällen före provet','Aldrig om du förstod genomgången'],0,'Kort repetition efter några dagar hjälper dig att behålla kunskapen längre.'],['Varför är blandad träning användbar?',['Den gör alla uppgifter enklare direkt','Du tränar på att välja rätt metod','Du slipper rätta dina svar'],1,'När uppgiftstyper blandas behöver du avgöra vilken metod som passar.'],['Vad gör du först när du fastnar i en ny typ av uppgift?',['Går direkt vidare utan att tänka','Tittar på ett genomarbetat exempel och hittar första oklara steget','Gissar tills svaret blir rätt'],1,'Ett tydligt exempel minskar belastningen och hjälper dig hitta precis vad du behöver fråga om.'],['Vilken reflektion efter rättning är mest användbar?',['Jag är dålig på detta','Vilket steg blev fel och vilken strategi testar jag nästa gång?','Hur många fel gjorde andra?'],1,'Metakognition handlar om att använda resultatet för att välja nästa steg.'],['Vad är ett bra studiepassmål?',['Plugga fysik länge','Bli klar med allt','Kunna beräkna hastighet i tre uppgifter med rätt enhet'],2,'Ett konkret mål visar både vad du tränar och hur du kan se att du lyckas.']] },
  { id:'matte-tal', nr:'02', title:'Matematik: tal, procent och enheter', desc:'Repetera grunden du behöver för beräkningar i fysik, kemi och teknik.', goals:['räkna säkert med positiva och negativa tal samt följa prioriteringsregler','växla mellan bråk, decimalform och procent','beräkna en andel, procentuell ökning och minskning','omvandla vanliga enheter och använda prefix','bedöma om ett svar är rimligt och skriva rätt enhet'], sections:[['1. Tal och räkneordning','<p>Börja med parenteser, sedan potenser, därefter multiplikation och division, och sist addition och subtraktion. Räkna från vänster när två räknesätt har samma prioritet.</p><p><strong>Exempel:</strong> 3 + 4 · 2 = 3 + 8 = 11. Men (3 + 4) · 2 = 14.</p><p>Negativa tal är vanliga i bland annat temperaturer och koordinatsystem. Minus framför ett tal visar riktning eller värde, inte “något konstigt”.</p>'],['2. Bråk, decimalform och procent','<p>De beskriver samma del av en helhet: <strong>1/2 = 0,5 = 50 %</strong>, <strong>1/4 = 0,25 = 25 %</strong> och <strong>3/4 = 0,75 = 75 %</strong>.</p><p><strong>Så växlar du:</strong> Bråk till decimalform: dividera täljaren med nämnaren. Decimalform till procent: multiplicera med 100. Procent till decimalform: dividera med 100.</p>'],['3. Procent i teknik och vardag','<p><strong>Andel:</strong> 15 % av 200 = 0,15 · 200 = 30.</p><p><strong>Ökning:</strong> Öka med 20 % betyder multiplicera med 1,20. <strong>Minskning:</strong> Minska med 20 % betyder multiplicera med 0,80.</p><p>Var noga: en ökning med 20 % och sedan en minskning med 20 % tar inte tillbaka dig till startvärdet. Procent räknas alltid på det aktuella värdet.</p>'],['4. Enheter och prefix','<p>Skriv alltid enhet i beräkningar. Det gör både lösningen tydligare och det lättare att upptäcka fel.</p><ul><li>1 m = 100 cm = 1 000 mm</li><li>1 kg = 1 000 g</li><li>1 L = 1 000 mL</li><li>1 km = 1 000 m</li><li>kilo (k) = 1 000, milli (m) = en tusendel och mikro (µ) = en miljondel</li></ul><p><strong>Tips:</strong> Byter du till en mindre enhet blir talet större: 2,5 m = 250 cm.</p>'],['5. Rimlighetsbedömning','<p>Gör en snabb uppskattning innan eller efter du räknar. Om en cyklist åker 10 km på ungefär en halvtimme är en hastighet på 0,2 km/h orimlig – då har något sannolikt gått fel.</p><p>Kontrollera: Är svaret i rätt storleksordning? Har jag rätt enhet? Är decimaltecknet på rätt plats? Är resultatet större eller mindre än det borde vara?</p>'],['Övning: tekniknära talträning','<ol><li>En komponent kostar 240 kr. Priset sänks med 15 %. Vad blir det nya priset?</li><li>En kabel är 1,75 m lång. Hur många millimeter är det?</li><li>Ett batteri laddas från 40 % till 65 %. Hur många procentenheter ökade laddningen?</li><li>En behållare rymmer 0,75 L. Hur många milliliter är det?</li><li>En mätning ger 0,004 A. Skriv värdet i milliampere.</li></ol><p><strong>Kontrollera sedan:</strong> Förklara med en mening vilken omvandling eller procentmetod du använde i varje uppgift.</p>']], example:'En solcell ger 180 W och dess effekt ökar med 10 %. Beräkna först ökningen: 0,10 · 180 W = 18 W. Lägg sedan till: 180 W + 18 W = 198 W. Rimlighetskontroll: en ökning med 10 % ska ge lite mer än 180 W, alltså är 198 W rimligt.', quiz:[['Vilken beräkning är korrekt?',['3 + 4 · 2 = 14','3 + 4 · 2 = 11','3 + 4 · 2 = 7'],1,'Multiplikation görs före addition: 4 · 2 = 8 och sedan 3 + 8 = 11.'],['Vilket tal är samma som 0,35?',['3,5 %','35 %','350 %'],1,'0,35 betyder 35 hundradelar, alltså 35 %.'],['Vilket är samma som 3/4?',['0,34','0,75','75,0'],1,'3 dividerat med 4 är 0,75, vilket också är 75 %.'],['Vad blir 25 % av 80?',['5','20','60'],1,'25 % = 0,25. Alltså 0,25 · 80 = 20.'],['En vara kostar 500 kr och sänks med 20 %. Vad blir nya priset?',['400 kr','480 kr','600 kr'],0,'Efter en minskning med 20 % återstår 80 %: 0,80 · 500 = 400 kr.'],['Hur många centimeter är 1,8 m?',['18 cm','180 cm','1 800 cm'],1,'En meter är 100 cm: 1,8 · 100 = 180 cm.'],['Vilket värde motsvarar 0,004 A?',['4 mA','40 mA','400 mA'],0,'En ampere är 1 000 milliampere: 0,004 A = 4 mA.'],['Vilken kontroll är bäst efter en beräkning?',['Att svaret har så många siffror som möjligt','Att enhet och storleksordning verkar rimliga','Att svaret blir ett heltal'],1,'Rätt enhet och rimlig storleksordning hjälper dig hitta vanliga misstag.']] },
  { id:'matte-algebra', nr:'03', title:'Matematik: algebra och formler', desc:'Använd variabler, ekvationer och formler i tekniknära beräkningar.', goals:['tolka variabler, uttryck och likhetstecknet','förenkla algebraiska uttryck genom att samla lika termer','lösa enkla ekvationer metodiskt och kontrollera lösningen','sätta in värden i en formel med rätt enheter','lösa ut en variabel ur en enkel formel'], sections:[['1. Variabler och uttryck','<p>En variabel är en bokstav som står för ett tal som kan vara okänt eller förändras. I <strong>3x + 2</strong> betyder 3x “tre gånger x”.</p><p>Likhetstecknet betyder att vänster och höger sida har samma värde. Det betyder inte “här kommer svaret”.</p><p><strong>Samla lika termer:</strong> 2x + 5x = 7x. Däremot kan du inte förenkla 2x + 5 till 7x, eftersom x-termer och vanliga tal inte är lika termer.</p>'],['2. Ekvationer – håll balansen','<p>En ekvation är som en balansvåg. Gör samma sak på båda sidor för att få variabeln ensam.</p><p><strong>Exempel:</strong> 3x + 4 = 19. Subtrahera 4 på båda sidor: 3x = 15. Dividera båda sidor med 3: x = 5.</p><p><strong>Kontroll:</strong> Sätt tillbaka x = 5 i ursprungsekvationen: 3 · 5 + 4 = 19. Det stämmer.</p>'],['3. Parenteser och distributiva lagen','<p>När ett tal står framför en parentes ska talet multipliceras med varje term i parentesen: 3(x + 4) = 3x + 12.</p><p>Räkna gärna ett talexempel för att kontrollera. Om x = 2 blir vänster sida 3(2 + 4) = 18 och höger sida 3 · 2 + 12 = 18.</p>'],['4. Formler beskriver samband','<p>Formler är ett kort sätt att skriva ett samband. I formeln <strong>v = s / t</strong> står v för hastighet, s för sträcka och t för tid.</p><p>Innan du räknar: skriv upp givna värden, enheter och vilken storhet du söker. Sätt sedan in värdena med parenteser om det behövs.</p><p><strong>Exempel:</strong> v = 120 m / 20 s = 6 m/s.</p>'],['5. Lösa ut en variabel','<p>Att lösa ut betyder att göra den variabel du söker ensam. Utgå från vad som händer med variabeln och gör motsatt räknesätt på båda sidor.</p><p>Ur v = s / t vill du lösa ut s. Multiplicera båda sidor med t: <strong>s = v · t</strong>.</p><p>Ur F = m · a vill du lösa ut a. Dividera båda sidor med m: <strong>a = F / m</strong>.</p>'],['6. Enheter är en del av formeln','<p>Enheter hjälper dig förstå om formeln används rätt. I s = v · t blir m/s · s = m. Sekunderna “tar ut” varandra och resultatet får enheten meter.</p><p>Om enheten inte verkar stämma: kontrollera om du har valt rätt formel, omvandlat enheter eller tappat ett räknesätt.</p>'],['Övning: algebra i teknik','<ol><li>Förenkla: 4x + 3x − 2.</li><li>Lös: 5x − 7 = 18.</li><li>Utveckla: 2(x + 6).</li><li>Hastigheten är v = 12 m/s och tiden är t = 15 s. Använd s = v · t för att beräkna sträckan.</li><li>I formeln P = U · I är P effekten. Lös ut I.</li></ol><p><strong>Metakognition:</strong> Skriv bredvid varje svar vilken regel eller formel du använde. Det gör ditt nästa repetitionspass mer träffsäkert.</p>']], example:'En robot åker 150 m på 30 s. Formeln är v = s / t. Sätt in värden med enheter: v = 150 m / 30 s = 5 m/s. Kontroll: 5 m/s under 30 s ger 5 · 30 = 150 m, alltså stämmer lösningen.', quiz:[['Vilka termer kan förenklas?',['2x + 5x','2x + 5','2 + 5x'],0,'Båda är x-termer: 2x + 5x = 7x.'],['Vilket är lösningen till 3x + 4 = 19?',['x = 5','x = 15','x = 23'],0,'Subtrahera 4: 3x = 15. Dela med 3: x = 5.'],['Vad är 3(x + 4)?',['3x + 4','3x + 7','3x + 12'],2,'Tre ska multipliceras med både x och 4.'],['Vad betyder v = s / t?',['Hastighet är sträcka dividerat med tid','Sträcka är hastighet dividerat med tid','Tid är sträcka gånger hastighet'],0,'v står för hastighet, s för sträcka och t för tid.'],['Vilken formel får du när s löses ut ur v = s / t?',['s = v / t','s = v · t','s = t / v'],1,'Multiplicera båda sidor med t så blir s ensamt.'],['I F = m · a, hur löser du ut a?',['a = F / m','a = F · m','a = m / F'],0,'Dividera båda sidor med m.'],['En bil kör 6 m/s under 10 s. Hur långt kör den?',['0,6 m','16 m','60 m'],2,'s = v · t = 6 m/s · 10 s = 60 m.'],['Varför ska du skriva enheter i en beräkning?',['De gör texten längre','De hjälper dig kontrollera att formeln och svaret verkar rimliga','De behövs bara på prov'],1,'Enheter visar vad talet betyder och kan avslöja felaktiga omvandlingar eller formler.']] },
  { id:'matte-grafer', nr:'04', title:'Matematik: grafer och geometri', desc:'Tolka samband, mätdata, ritningar och tekniska mått.', goals:['läsa av och beskriva information i ett koordinatsystem och en graf','förklara lutning och skärning med y-axeln i ett linjärt samband','skilja på proportionella och andra linjära samband','beräkna omkrets, area och volym med rätt enhet','använda skala och Pythagoras sats i enkla tekniska situationer'], sections:[['1. Koordinatsystem och grafer','<p>En punkt skrivs <strong>(x, y)</strong>. x-värdet visar läget i sidled och y-värdet läget uppåt eller nedåt.</p><p>Innan du tolkar en graf: läs rubriken, undersök vad båda axlarna visar, kontrollera enheterna och titta på skalan. En graf är ett sätt att visa hur två storheter hänger ihop.</p>'],['2. Linjära och proportionella samband','<p>Ett linjärt samband kan skrivas <strong>y = kx + m</strong>. k är lutningen, alltså hur mycket y förändras när x ökar med ett steg. m är värdet där grafen skär y-axeln.</p><p>Ett proportionellt samband har formen <strong>y = kx</strong>. Grafen går då genom origo (0, 0). Exempel: om varje meter kabel kostar lika mycket blir kostnaden proportionell mot längden.</p>'],['3. Lutning i tekniska diagram','<p>I en sträcka–tid-graf visar lutningen hastigheten. En brantare linje betyder högre hastighet. En vågrät linje betyder att sträckan inte förändras – objektet står still.</p><p>Beräkna lutning som förändringen i y delat med förändringen i x. Skriv alltid vilken storhet lutningen beskriver och dess enhet.</p>'],['4. Omkrets, area och volym','<p><strong>Omkrets</strong> är längden runt en figur och mäts i exempelvis cm eller m. <strong>Area</strong> är ytan innanför och mäts i cm² eller m². <strong>Volym</strong> är utrymmet i en kropp och mäts i cm³, m³ eller liter.</p><ul><li>Rektangel: area = längd · bredd</li><li>Triangel: area = bas · höjd / 2</li><li>Rätblock: volym = längd · bredd · höjd</li></ul>'],['5. Skala i ritningar','<p>En skala visar sambandet mellan måttet på ritningen och verkligheten. Skala 1:50 betyder att 1 cm på ritningen motsvarar 50 cm i verkligheten.</p><p>Skriv tydligt om du räknar från ritning till verklighet eller tvärtom. Kontrollera att båda måtten är i samma enhet innan du jämför.</p>'],['6. Pythagoras sats','<p>I en rätvinklig triangel gäller <strong>a² + b² = c²</strong>, där c är hypotenusan – sidan mitt emot den räta vinkeln.</p><p>Exempel: en rätvinklig triangel har kateterna 3 m och 4 m. Då är c² = 3² + 4² = 9 + 16 = 25, alltså c = 5 m.</p>'],['Övning: mätdata och konstruktion','<ol><li>En punkt ligger 4 steg åt höger och 3 steg upp. Skriv koordinaten.</li><li>I en sträcka–tid-graf ökar sträckan från 20 m till 80 m på 10 s. Beräkna lutningen och förklara vad den betyder.</li><li>En rektangulär platta är 30 cm · 20 cm. Beräkna area och omkrets.</li><li>En låda är 40 cm lång, 30 cm bred och 20 cm hög. Beräkna volymen.</li><li>En ritning har skala 1:100. En vägg är 4,5 cm på ritningen. Hur lång är väggen i verkligheten?</li><li>En stege ska nå 5 m upp på en vägg och står 12 m från väggen. Hur lång måste stegen vara?</li></ol><p><strong>Kontrollera:</strong> Vilken enhet ska varje svar ha? Varför?</p>']], example:'En rätvinklig stödkonstruktion har sidorna 6 m och 8 m längs den räta vinkeln. Pythagoras sats ger c² = 6² + 8² = 36 + 64 = 100. Alltså c = 10 m. Rimlighetskontroll: hypotenusan ska vara längre än både 6 m och 8 m, så 10 m är rimligt.', quiz:[['Vad ska du kontrollera först när du läser en graf?',['Vilken färg linjen har','Vad axlarna och enheterna visar','Hur många punkter som finns'],1,'Axlar, enheter och skala visar vad grafen faktiskt berättar.'],['Vad visar lutningen i en sträcka–tid-graf?',['Hur snabbt sträckan förändras','Starttiden','Grafens färg'],0,'Lutningen beskriver förändring per tidsenhet – här hastighet.'],['Vilket samband är proportionellt?',['y = 3x','y = 3x + 2','y = x²'],0,'Ett proportionellt samband går genom origo och har formen y = kx.'],['Vilken enhet passar en area?',['cm','cm²','cm³'],1,'Area är tvådimensionell och mäts i kvadratenheter.'],['Vilken enhet passar volym?',['cm','cm²','cm³'],2,'Volym är tredimensionell och mäts i kubikenheter.'],['En rektangel är 4 m lång och 2 m bred. Vad är arean?',['6 m²','8 m²','12 m²'],1,'Area = längd · bredd = 4 · 2 = 8 m².'],['Vad betyder skala 1:50?',['1 cm på ritningen är 50 cm i verkligheten','50 cm på ritningen är 1 cm i verkligheten','Ritningen är 50 gånger större än verkligheten'],0,'Skala 1:50 betyder att ritningen är förminskad 50 gånger.'],['En rätvinklig triangel har kateterna 3 m och 4 m. Hur lång är hypotenusan?',['5 m','7 m','12 m'],0,'3² + 4² = 9 + 16 = 25 och roten ur 25 är 5.']] },
  { id:'fysik', nr:'05', title:'Fysik från grundskolan', desc:'Repetera fysiken du behöver för teknikprogrammets beräkningar, laborationer och modeller.', goals:['använda vanliga fysikaliska storheter, SI-enheter och prefix','beräkna och tolka hastighet samt rörelse i diagram','identifiera krafter och beskriva deras påverkan på rörelse','förklara energiomvandlingar, energiprincipen, effekt och verkningsgrad på grundnivå','förklara ström, spänning, resistans och enkla elektriska kretsar','presentera mätresultat i tabell, graf och kort laborationsslutsats'], sections:[['1. Mätning, storheter och enheter','<p>Fysik beskriver världen med <strong>storheter</strong>, tal och enheter. Exempel: sträcka (m), tid (s), massa (kg), temperatur (°C), kraft (N), energi (J), effekt (W), ström (A) och spänning (V).</p><p>Skriv alltid enhet i beräkningen. Anpassa enheter innan du använder en formel, till exempel km/h till m/s när uppgiften kräver det.</p><p>Alla mätningar har en viss osäkerhet. Läs instrumentets skala noga, gör flera mätningar när det behövs och avrunda inte mer exakt än instrumentet tillåter.</p>'],['2. Rörelse och hastighet','<p>Hastighet visar hur långt något rör sig per tidsenhet: <strong>v = s / t</strong>. Sträcka mäts ofta i meter, tid i sekunder och hastighet i m/s.</p><p>I en sträcka–tid-graf visar lutningen hastigheten. En brant linje betyder högre hastighet. En vågrät linje betyder att objektet står still.</p><p><strong>Exempel:</strong> 150 m på 30 s ger v = 150 / 30 = 5 m/s.</p>'],['3. Krafter och rörelseförändring','<p>En kraft kan ändra ett föremåls fart, riktning eller form. Kraft mäts i newton (N).</p><p>Vanliga krafter är tyngdkraft, friktionskraft, normalkraft och dragkraft. Rita dem som pilar: pilens riktning visar åt vilket håll kraften verkar och längden kan visa hur stor kraften är.</p><p>När krafterna är i balans förändras inte rörelsen. När kraftresultanten inte är noll förändras rörelsen, till exempel genom att föremålet accelererar eller bromsar.</p>'],['4. Energi, effekt och hållbar teknik','<p>Energi kan inte skapas eller förstöras – den omvandlas och överförs. Exempel: i en elcykel omvandlas kemisk energi i batteriet till elektrisk energi, rörelseenergi, värme och ljud.</p><p><strong>Effekt</strong> beskriver hur snabbt energi omvandlas eller används. Enheten är watt (W). <strong>Verkningsgrad</strong> beskriver hur stor andel av den tillförda energin som blir den energi vi vill ha.</p><p>Jämför energikällor genom att väga in funktion, effektivitet, miljöpåverkan och samhällskonsekvenser.</p>'],['5. Elektricitet och kretsar','<p><strong>Ström</strong> (A) är laddningar som rör sig i en sluten krets. <strong>Spänning</strong> (V) driver strömmen. <strong>Resistans</strong> (Ω) bromsar strömmen.</p><p>I en seriekoppling går samma ström genom alla komponenter. I en parallellkoppling har varje gren samma spänning som spänningskällan och andra grenar kan fortfarande fungera om en lampa går sönder.</p><p>Elektrisk effekt kan beräknas med <strong>P = U · I</strong>. Använd alltid rätt enheter: W = V · A.</p>'],['6. Undersökningar, tabeller och diagram','<p>En enkel laboration behöver en undersökningsbar fråga, en plan, mätvärden, resultat och slutsats. Skilj på <strong>resultat</strong> (vad du mätte) och <strong>slutsats</strong> (vad resultatet kan betyda).</p><p>Välj en tydlig rubrik och enhet på axlarna i diagram. Fundera på felkällor: Vad kan ha påverkat mätningen? Hur kan metoden förbättras?</p>'],['Övning: fysik i teknik','<ol><li>En drönare flyger 240 m på 40 s. Beräkna medelhastigheten.</li><li>Rita kraftpilar för en bok som ligger stilla på ett bord. Vilka två krafter verkar?</li><li>Beskriv minst tre energiomvandlingar i en mobiltelefon när den används.</li><li>En apparat har spänningen 12 V och strömmen 2 A. Beräkna effekten.</li><li>Förklara varför lamporna hemma vanligtvis är parallellkopplade.</li><li>Du undersöker hur lutning påverkar en bils hastighet. Vad kan vara en felkälla och hur kan du minska den?</li></ol><p><strong>Metakognition:</strong> Markera vilka uppgifter som kräver en formel, en modell eller en förklaring med egna ord.</p>']], example:'En liten motor är kopplad till 9 V och drar 0,30 A. Använd P = U · I: P = 9 V · 0,30 A = 2,7 W. Enhetskontroll: volt gånger ampere blir watt. Rimlighetskontroll: en liten motor använder några watt, så svaret är rimligt.', quiz:[['Vilken enhet används för kraft?',['Newton','Joule','Volt'],0,'Kraft mäts i newton (N).'],['En cyklist åker 300 m på 60 s. Hur stor är hastigheten?',['0,2 m/s','5 m/s','18 000 m/s'],1,'v = s / t = 300 m / 60 s = 5 m/s.'],['Vad visar lutningen i en sträcka–tid-graf?',['Hastigheten','Massan','Temperaturen'],0,'Lutningen visar hur snabbt sträckan förändras med tiden.'],['Vilken kraft drar föremål mot jorden?',['Friktion','Tyngdkraft','Magnetisk kraft'],1,'Tyngdkraften drar föremål mot jordens centrum.'],['Vad säger energiprincipen?',['Energi kan skapas av ingenting','Energi kan förstöras helt','Energi omvandlas och överförs men bevaras totalt'],2,'Energi kan byta form och flyttas mellan system, men den totala mängden bevaras.'],['Vilken enhet används för elektrisk ström?',['Volt','Ampere','Ohm'],1,'Elektrisk ström mäts i ampere (A).'],['En apparat har U = 6 V och I = 0,5 A. Hur stor är effekten?',['3 W','6,5 W','12 W'],0,'P = U · I = 6 · 0,5 = 3 W.'],['Varför är en laborationsslutsats inte samma sak som resultatet?',['Slutsatsen tolkar vad mätresultaten kan betyda','Slutsatsen måste alltid vara längre','Resultat får inte innehålla siffror'],0,'Resultat visar observationer och mätvärden; slutsatsen använder dem för att besvara frågan.']] },
  { id:'kemi', nr:'06', title:'Kemi från grundskolan', desc:'Repetera kemin som behövs för material, energi, laborationer och hållbar teknik.', goals:['förklara skillnaden mellan atom, grundämne, molekyl och jon','hitta och använda information i periodiska systemet på grundnivå','tolka enkla kemiska formler och reaktionsformler','förklara vad blandningar, lösningar och koncentration betyder','beskriva syror, baser, pH och enkel neutralisation','använda faropiktogram och grundläggande laborationssäkerhet'], sections:[['1. Materia och partiklar','<p>All materia består av partiklar. En <strong>atom</strong> har en kärna med protoner och neutroner samt elektroner runt kärnan. Ett <strong>grundämne</strong> består av en sorts atomer.</p><p>En <strong>molekyl</strong> består av atomer som sitter ihop. En <strong>jon</strong> är en atom eller grupp av atomer med elektrisk laddning, eftersom den har tagit upp eller lämnat ifrån sig elektroner.</p><p>Partikelmodellen hjälper oss förstå fast form, vätska och gas: partiklarna sitter tätare i fasta ämnen och rör sig friare i gaser.</p>'],['2. Periodiska systemet','<p>Periodiska systemet ordnar grundämnen efter atomnummer. Rutan för varje grundämne visar bland annat kemiskt tecken och atomnummer.</p><p>Metaller finns främst till vänster och i mitten, medan många icke-metaller finns till höger. Metaller leder ofta värme och elektricitet, men olika metaller har olika egenskaper.</p><p><strong>Exempel:</strong> Fe är järn, Cu är koppar, O är syre och C är kol. Lär dig läsa tecknet exakt – stor och liten bokstav spelar roll.</p>'],['3. Bindningar, formler och reaktioner','<p>Atomer kan bindas på olika sätt. I enkla kemiska formler visar en liten siffra hur många atomer av ämnet som finns i en partikel. <strong>H₂O</strong> betyder två väteatomer och en syreatom.</p><p>En kemisk reaktion innebär att atomerna ordnas om och nya ämnen bildas. Atomer försvinner inte; därför behöver samma sorts atomer finnas på båda sidor i en balanserad reaktionsformel.</p><p><strong>Exempel:</strong> 2H₂ + O₂ → 2H₂O. Det finns fyra väteatomer och två syreatomer både före och efter reaktionen.</p>'],['4. Blandningar, lösningar och separation','<p>En <strong>blandning</strong> innehåller flera ämnen. I en <strong>lösning</strong> är ett ämne jämnt fördelat i ett annat, till exempel salt löst i vatten.</p><p>Koncentration beskriver hur mycket löst ämne som finns i en viss mängd lösning. Man kan separera ämnen med exempelvis filtrering, indunstning, destillation eller kromatografi – metoden väljs efter ämnenas egenskaper.</p>'],['5. Syror, baser och pH','<p>pH-skalan används för att beskriva hur sur eller basisk en vattenlösning är. pH under 7 är surt, pH 7 är neutralt och pH över 7 är basiskt.</p><p>Syror och baser kan reagera med varandra i en neutralisation. Arbeta alltid säkert: även vanliga ämnen kan vara frätande i hög koncentration.</p>'],['6. Material, oxidation och hållbar teknik','<p>Material väljs efter egenskaper som hållfasthet, ledningsförmåga, vikt, korrosionsbeständighet och möjlighet till återvinning. Kemi hjälper oss förstå varför koppar används i kablar, varför stål kan rosta och varför batterier fungerar.</p><p><strong>Oxidation</strong> innebär att ett ämne reagerar med syre eller lämnar ifrån sig elektroner. Rost är ett exempel på korrosion, en oönskad kemisk reaktion som kan förebyggas med färg, legeringar eller galvanisering.</p>'],['7. Laborationssäkerhet och dokumentation','<p>Läs alltid instruktioner och faropiktogram före en laboration. Använd skyddsglasögon när det behövs, håll ordning på kemikalier och rapportera spill eller olyckor direkt.</p><p>Dokumentera vad du gör, vad du observerar och vad du drar för slutsats. Blanda aldrig kemikalier på eget initiativ och smaka aldrig på laboratoriematerial.</p>'],['Övning: kemi i teknik','<ol><li>Förklara skillnaden mellan en atom, en molekyl och en jon med egna ord.</li><li>Hitta Fe, Cu och O i periodiska systemet. Vilka är metaller respektive icke-metall?</li><li>Hur många väteatomer och syreatomer finns i 3H₂O?</li><li>Vilken separationsmetod kan användas för att få fram salt ur saltvatten? Förklara varför.</li><li>En lösning har pH 3. Är den sur, neutral eller basisk?</li><li>Ge två exempel på hur korrosion kan förebyggas i en konstruktion.</li><li>Välj ett faropiktogram och förklara vilken säkerhetsåtgärd det leder till.</li></ol><p><strong>Metakognition:</strong> Markera vilka svar som bygger på begrepp, vilka som bygger på modeller och vilka som kräver en säkerhetsbedömning.</p>']], example:'En batteritillverkare jämför koppar och plast i en ledning. Koppar är en metall som leder elektrisk ström väl, medan plast är en isolator. Därför används koppar ofta som ledare och plast som skyddande hölje. Materialvalet bygger alltså på kemiska och fysikaliska egenskaper, inte bara på pris eller utseende.', quiz:[['Vad består ett grundämne av?',['En sorts atomer','Alltid två olika atomer','Endast molekyler'],0,'Ett grundämne består av en sorts atomer.'],['Vad betyder formeln H₂O?',['Två syreatomer och en väteatom','Två väteatomer och en syreatom','Två vattenmolekyler'],1,'Den lilla tvåan hör till H och visar två väteatomer.'],['Vad visar det periodiska systemet?',['Grundämnen','Alla molekyler','Endast metaller'],0,'Periodiska systemet är en ordning av grundämnen.'],['Vad är en jon?',['En atom eller atomgrupp med elektrisk laddning','En atom utan elektroner','Ett annat namn för molekyl'],0,'Joner får laddning när elektroner tas upp eller lämnas ifrån.'],['Vilken metod kan användas för att få salt från saltvatten?',['Filtrering av saltet direkt','Indunstning av vattnet','Magnetisering'],1,'När vattnet indunstar blir saltet kvar.'],['Vad innebär pH 7 ungefär?',['Surt','Neutralt','Basiskt'],1,'På den vanliga pH-skalan är 7 neutralt.'],['Vad är rost ett exempel på?',['Korrosion','Neutralisation','Filtrering'],0,'Rost är korrosion av järn.'],['Vilket är ett säkert laborationsbeteende?',['Smaka på ett okänt ämne för att identifiera det','Läsa faropiktogram och använda skyddsglasögon vid behov','Blanda kemikalier för att se vad som händer'],1,'Följ alltid instruktioner, faropiktogram och säkerhetsrutiner.']] },
  { id:'svenska', nr:'07', title:'Svenska', desc:'Läs, förstå och uttryck dig tydligt i teknik- och naturvetenskapliga ämnen.', goals:['förstå vad en uppgift faktiskt ber om','använda lässtrategier för faktatexter, instruktioner, diagram och uppgifter','förklara ämnesinnehåll med relevanta begrepp och sambandsord','skriva tydliga svar, resonemang och enkla rapportdelar','sammanfatta en text och ange en källa på grundnivå'], sections:[['1. Språket är ett verktyg för att tänka','<p>I teknik och naturvetenskap behöver du inte bara kunna ett svar – du behöver visa <strong>hur</strong> du tänker. Ämnesspråk gör det möjligt att vara exakt.</p><p>Jämför: “Det blev varmt” med “Temperaturen ökade eftersom elektrisk energi omvandlades till värme i resistorn.” Den andra meningen använder begrepp och visar ett samband.</p><p>Bygg en egen begreppsbank. Skriv ordet, en enkel förklaring, ett exempel och gärna en bild eller symbol.</p>'],['2. Läs en uppgift strategiskt','<p>Läs först hela uppgiften. Markera sedan <strong>uppgiftsverbet</strong> – det talar om vad du ska göra.</p><ul><li><strong>Beräkna:</strong> visa formel, insättning, beräkning och enhet.</li><li><strong>Förklara:</strong> beskriv hur eller varför något fungerar.</li><li><strong>Jämför:</strong> visa likheter och skillnader.</li><li><strong>Resonera:</strong> utveckla tanken med orsaker, konsekvenser och exempel.</li><li><strong>Beskriv:</strong> återge viktiga delar eller steg tydligt.</li></ul><p>Skriv om frågan med egna ord innan du svarar om den känns svår.</p>'],['3. Läs faktatexter, diagram och instruktioner','<p>Börja med rubrik, mellanrubriker, bilder, bildtexter och ord i fetstil. Fråga: Vad handlar texten om? Vilka begrepp måste jag förstå? Vilka samband visar texten?</p><p>När du läser en instruktion: numrera stegen, markera material och säkerhetsinformation och kontrollera vad resultatet ska bli. När du läser ett diagram: läs rubrik, axlar, enheter och skala före du drar en slutsats.</p>'],['4. Skriv förklaringar och resonemang','<p>Använd den här enkla modellen: <strong>påstående → förklaring → exempel → slutsats</strong>.</p><p><strong>Exempel:</strong> “Metall är lämpligt i en elkabel eftersom metaller leder elektrisk ström. Koppar har god ledningsförmåga och används därför ofta som ledare. Plast kan i stället användas runt kabeln eftersom plast isolerar.”</p><p>Hjälp läsaren att följa ditt tänkande med sambandsord: eftersom, därför, vilket leder till, däremot, till exempel, först, sedan och slutligen.</p>'],['5. Svara med precision','<p>Ett bra svar är varken enstavigt eller onödigt långt. Svara på just frågan, använd minst ett relevant begrepp och visa ett led i ditt tänkande.</p><p>Vid beräkningar: skriv formel, värden med enheter, svar och rimlighetskontroll. Vid laborationer: skilj mellan observation, resultat och slutsats.</p>'],['6. Sammanfatta och använda källor','<p>En sammanfattning tar med huvudidén och de viktigaste delarna med egna ord. Kopiera inte hela meningar. Kontrollera vem som står bakom informationen, när den publicerades och varför den finns.</p><p>När du använder en källa: skriv så att läsaren kan hitta den, till exempel organisation/författare, titel och länk. Skilj alltid på vad källan säger och din egen förklaring.</p>'],['7. Muntlig redovisning','<p>En tydlig presentation har en enkel struktur: inledning, två eller tre huvudpunkter och en avslutning. Använd bilder och diagram som stöd, men låt inte bilden ersätta din förklaring.</p><p>Öva på att förklara ett begrepp för en klasskamrat utan att läsa innantill. Frågor från andra visar vilka delar som behöver bli tydligare.</p>'],['Övning: språk för teknik och naturvetenskap','<ol><li>Skriv om uppmaningen “Resonera om för- och nackdelar med solenergi” med egna ord. Vad måste svaret innehålla?</li><li>Förklara skillnaden mellan “beräkna” och “förklara”.</li><li>Gör en begreppsbank för orden effekt, energi, spänning och resistans.</li><li>Skriv ett stycke med påstående, förklaring och exempel: Varför används koppar i elkablar?</li><li>Läs en kort faktatext och skriv en sammanfattning på tre meningar med egna ord.</li><li>Hitta en källa om återvinning. Skriv vem som står bakom den och varför den verkar trovärdig.</li></ol><p><strong>Metakognition:</strong> Vilken del är svårast för dig: förstå frågan, hitta ämnesord, bygga meningar eller bedöma källor? Välj en strategi till nästa gång.</p>']], example:'Uppgiften lyder: “Förklara varför en cykel bromsar när du slutar trampa.” Ett starkt svar kan vara: “Cykeln bromsar eftersom friktion mellan däck och mark samt luftmotstånd verkar mot rörelsen. Rörelseenergi omvandlas samtidigt till värme och ljud. Därför minskar cykelns hastighet även utan att bromsarna används.”', quiz:[['Vilket är det första du bör hitta i en uppgift?',['Uppgiftsverbet, till exempel förklara eller beräkna','Det längsta ordet','Antalet rader'],0,'Uppgiftsverbet visar vilken typ av svar frågan behöver.'],['Vilket ord visar en förklaring av orsak?',['eftersom','först','till slut'],0,'“Eftersom” kopplar ihop en orsak med en följd.'],['Vad behöver ett svar på “jämför” innehålla?',['Bara ett exempel','Likheter och skillnader','Endast en beräkning'],1,'En jämförelse visar minst en likhet och en skillnad.'],['Vilken ordning passar en enkel förklaring?',['Slutsats → rubrik → bild','Påstående → förklaring → exempel → slutsats','Mening → siffra → punkt'],1,'Modellen hjälper läsaren att följa resonemanget.'],['Vad ska du kontrollera först i ett diagram?',['Axlar, enheter och skala','Vilken färg staplarna har','Om diagrammet är stort'],0,'Axlar, enheter och skala visar vad informationen betyder.'],['Vad skiljer resultat från slutsats i en laboration?',['Resultatet är mätvärden; slutsatsen tolkar dem','Resultat skrivs bara i punktform','Slutsatsen får inte använda resultatet'],0,'Resultat beskriver vad du observerade eller mätte; slutsatsen besvarar frågan med hjälp av resultatet.'],['Vad är en sammanfattning?',['En kopia av hela texten','Huvudidéer och viktiga delar med egna ord','Bara en egen åsikt'],1,'Sammanfattningen återger det viktigaste kort med egna ord.'],['Vilken källa är bäst att börja med för fakta om ett skolämne?',['En okänd kommentar i sociala medier','En myndighet, ett universitet eller annan tydlig sakkunnig avsändare','En sida utan författare eller datum'],1,'En tydlig, sakkunnig avsändare gör det lättare att bedöma informationens trovärdighet.']] },
  { id:'digitalt', nr:'09', title:'Digital grundkompetens', desc:'Filer, dokument, kalkylark och säkerhet.', goals:['hantera filer och mappar på ett ordnat sätt','skapa enkla dokument och diagram','skydda konton och känna igen vanliga risker'], sections:[['Ordning sparar tid','Använd tydliga filnamn: datum_uppgift_version. Spara i rätt mapp och ha en säker kopia i molnet.'],['Säker digital vardag','Använd långa unika lösenord och tvåfaktorsautentisering. Kontrollera avsändare och länkar innan du loggar in.']], example:'En bra mappstruktur kan vara: Teknik / Fysik / Laboration_energi / rapport_v1.docx.', quiz:[['Vad är bäst för ett viktigt skolarbete?',['Spara bara på datorns skrivbord','Spara i tydlig mapp och ha en säker kopia','Byta filnamn varje gång utan struktur'],1,'En tydlig struktur och säkerhetskopia minskar risken att förlora arbete.'],['Vad är en varningssignal för nätfiske?',['Ett oväntat meddelande som vill att du loggar in snabbt','En uppgift från din lärare i Classroom','En sparad fil på din dator'],0,'Brådska och oväntade inloggningslänkar är vanliga varningssignaler.']] }
];

const digitaltChapter = chapters.find(chapter => chapter.id === 'digitalt');
digitaltChapter.nr = '02';
chapters.find(chapter => chapter.id === 'matte-tal').nr = '03';
chapters.find(chapter => chapter.id === 'matte-algebra').nr = '04';
chapters.find(chapter => chapter.id === 'matte-grafer').nr = '05';
chapters.find(chapter => chapter.id === 'fysik').nr = '06';
chapters.find(chapter => chapter.id === 'kemi').nr = '07';
chapters.find(chapter => chapter.id === 'svenska').nr = '08';
digitaltChapter.desc = 'Praktiska arbetssätt för macOS, Finder, Google Drive, filer, mappar och kortkommandon.';
digitaltChapter.goals = ['skapa och använda en tydlig mappstruktur på Mac och i Google Drive','namnge, hitta, flytta och dela filer på ett genomtänkt sätt','förstå skillnaden mellan Min enhet, Delas med mig och delade mappar','välja rätt delningsbehörighet i Google Drive','använda vanliga macOS-kortkommandon för att arbeta snabbare och säkrare','skydda sitt skolarbete genom ordning, versioner och ansvarsfull delning'];
digitaltChapter.sourceNote = `<p><strong>Varför detta kapitel?</strong> Digital ordning minskar stress, sparar tid och gör det lättare att visa sin arbetsprocess. Google rekommenderar bland annat meningsfulla filnamn, mappar och undermappar samt genvägar till material som delas med dig. <a href="https://support.google.com/drive/answer/2375091?co=GENIE.Platform%3DDesktop&hl=sv" target="_blank" rel="noopener">Googles guide: Ordna dina filer på Drive</a>.</p><p>macOS-kortkommandon kan spara många små klick. Apple påpekar att kortkommandon kan skilja sig mellan appar och tangentbordslayouter – kontrollera därför alltid appens menyer om ett kommando inte fungerar. <a href="https://support.apple.com/sv-se/102650" target="_blank" rel="noopener">Apples kortkommandon på Mac</a>.</p>`;
digitaltChapter.sections = [['1. Börja med en struktur som håller','<p>Skapa en huvudmapp för skolarbetet och använd samma struktur lokalt på Mac och i Google Drive. Lägg inte viktiga filer löst på skrivbordet eller bara i Hämtade filer.</p><p><strong>Förslag:</strong></p><ul><li>Skola<ul><li>Åk 1 Teknik<ul><li>Matematik → Kapitel_01 och Prov_och_repetition</li><li>Fysik → Laborationer och Presentationer</li><li>Kemi</li><li>Teknik</li><li>Gemensamt</li></ul></li></ul></li></ul><p>Skapa inte fler mappnivåer än du behöver. Tre till fyra nivåer räcker oftast.</p>'],['2. Finder på macOS: hitta, skapa och flytta','<p><strong>Finder</strong> är platsen där du hanterar filer på Mac. Öppna Finder via ikonen i Dock. I sidofältet är särskilt <strong>Hämtade filer</strong>, <strong>Dokument</strong>, <strong>Skrivbord</strong> och din Drive-mapp viktiga.</p><ol><li>Öppna rätt huvudmapp i Finder.</li><li>Skapa en ny mapp med <strong>Skift-⌘-N</strong> eller Arkiv → Ny mapp.</li><li>Ge mappen ett tydligt namn direkt.</li><li>Dra filen till rätt mapp eller använd klipp ut och klistra in.</li><li>Kontrollera att filen verkligen hamnade där genom att öppna mappen.</li></ol><p><strong>Veckorutin:</strong> Töm inte Hämtade filer blint. Flytta i stället nya skolfiler till rätt kursmapp samma dag.</p>'],['3. Namnge filer så att du hittar dem igen','<p>Ett bra filnamn berättar vad filen är, när den skapades och vilken version som är aktuell.</p><p><strong>Rekommenderad modell:</strong> <code>ÅÅÅÅ-MM-DD_ämne_uppgift_v01</code></p><ul><li><code>2026-08-24_fysik_laboration-rorelse_v01</code></li><li><code>2026-09-03_teknik_konstruktion-ritning_v02</code></li><li><code>2026-09-10_matematik_procent-repetition</code></li></ul><p>Undvik namn som <code>ny</code>, <code>slutlig</code>, <code>slutlig2</code> och <code>dokument</code>. När något faktiskt är klart kan du skriva <code>klar</code> eller exportera en PDF.</p>'],['4. Google Drive: Min enhet, Delas med mig och genvägar','<p><strong>Min enhet</strong> är din egen organiserade yta. Skapa mappar med Ny → Ny mapp, och flytta eller dra in egna filer där.</p><p><strong>Delas med mig</strong> visar material andra har delat med dig. Du ska normalt inte försöka flytta lärarens eller klassens original till din egen mapp. Lägg i stället till en <strong>genväg</strong> till din kursmapp: högerklicka på filen eller mappen → Ordna → Lägg till genväg. Då hittar du materialet utan att ändra dess plats.</p><p>Om skolan använder delade enheter följer filer och mappar organisationens regler. Fråga läraren innan du flyttar gemensamt material.</p>'],['5. Dela rätt – och bara med rätt personer','<p>När du delar i Google Drive väljer du vem som får åtkomst och vad personen får göra:</p><ul><li><strong>Läsbehörig:</strong> kan öppna och läsa.</li><li><strong>Kommentator:</strong> kan läsa och lämna kommentarer.</li><li><strong>Redigerare:</strong> kan ändra innehållet.</li></ul><p>Dela helst med namngivna personer eller skolkonton, inte med en öppen länk om det inte är meningen. Kom ihåg att behörigheter i en delad mapp ofta ärvs av filerna i mappen. Kontrollera alltid vem som har åtkomst före inlämning.</p>'],['6. Dokument, PDF och versioner','<p>Skriv i Google Dokument när du ska samarbeta eller lämna in enligt lärarens instruktion. Exportera till PDF när layouten ska vara låst: Arkiv → Hämta → PDF.</p><p>När du gör större ändringar: skapa en tydlig ny version, till exempel <code>v02</code>. Spara inte flera helt olika arbeten med nästan samma otydliga namn. Lägg inte lösenord eller känslig information i filnamn.</p><p><strong>Innan inlämning:</strong> öppna filen från Drive, kontrollera namn och version, kontrollera delning och öppna PDF-filen en gång.</p>'],['7. Kortkommandon som alla bör kunna','<table class="shortcut-table"><thead><tr><th>Kortkommando</th><th>Gör detta</th></tr></thead><tbody><tr><td>⌘ C</td><td>Kopiera</td></tr><tr><td>⌘ V</td><td>Klistra in</td></tr><tr><td>⌘ X</td><td>Klipp ut</td></tr><tr><td>⌘ A</td><td>Markera allt</td></tr><tr><td>⌘ Z</td><td>Ångra</td></tr><tr><td>Skift-⌘ Z</td><td>Gör om</td></tr><tr><td>⌘ S</td><td>Spara</td></tr><tr><td>⌘ F</td><td>Sök i dokument eller fönster</td></tr><tr><td>⌘ N</td><td>Nytt dokument eller nytt fönster</td></tr><tr><td>⌘ O</td><td>Öppna fil</td></tr><tr><td>⌘ W</td><td>Stäng aktuellt fönster eller flik</td></tr><tr><td>⌘ Q</td><td>Avsluta appen</td></tr><tr><td>⌘ Mellanslag</td><td>Öppna Spotlight och sök efter appar eller filer</td></tr><tr><td>⌘ Tab</td><td>Växla mellan öppna appar</td></tr><tr><td>Skift-⌘ N</td><td>Skapa ny mapp i Finder</td></tr><tr><td>Mellanslag</td><td>Förhandsvisa markerad fil i Finder</td></tr><tr><td>Skift-⌘ 3</td><td>Skärmbild av hela skärmen</td></tr><tr><td>Skift-⌘ 4</td><td>Välj område för skärmbild</td></tr></tbody></table><p>Obs: kortkommandon kan skilja sig mellan appar. Titta i menyraden i appen om ett kommando inte fungerar.</p>'],['8. Digital säkerhet och ansvar','<p>Använd skolkontot på skolmaterial, logga ut från delade datorer och godkänn inte oväntade inloggningsförfrågningar. Kontrollera avsändare och länk innan du loggar in.</p><p>Dela aldrig ett lösenord. Använd ett långt, unikt lösenord och tvåfaktorsautentisering när skolan erbjuder det. Fråga läraren om du är osäker på om en fil eller länk är legitim.</p>'],['Praktisk startuppgift','<ol><li>Skapa mappstrukturen <strong>Skola → Åk 1 Teknik → Fysik → Laborationer</strong> i Drive.</li><li>Skapa ett dokument i mappen och döp det till <code>2026-08-24_fysik_laboration-test_v01</code>.</li><li>Skriv tre rader i dokumentet och byt sedan filnamnet till version <code>v02</code>.</li><li>Lägg till en genväg till en fil från Delas med mig i en relevant kursmapp.</li><li>Öva fem kortkommandon: ⌘ C, ⌘ V, ⌘ Z, ⌘ F och Skift-⌘ N.</li><li>Dela dokumentet med en klasskamrat som <strong>Kommentator</strong>. Kontrollera sedan vilken åtkomst personen har.</li><li>Exportera dokumentet som PDF och kontrollera att både dokument och PDF ligger i rätt mapp.</li></ol><p><strong>Metakognition:</strong> Vad tog längst tid? Vilket steg kan du göra annorlunda nästa gång för att hålla ordning från början?</p>']];
digitaltChapter.example = 'Du har laddat ned en laborationsmall till Hämtade filer. Flytta den först till Skola/Åk 1 Teknik/Fysik/Laborationer. Döp den sedan till 2026-08-24_fysik_laboration-rorelse_v01. Om läraren delade mallen via Drive: skapa i stället en genväg till den, eller gör en egen kopia om läraren har bett om det. Då vet du både var originalet finns och var ditt eget arbete ligger.';
digitaltChapter.quiz = [['Var bör en viktig skolfils slutversion ligga?',['Bara på skrivbordet','I en tydlig kursmapp i Drive och/eller enligt skolans rutin','Endast i Hämtade filer'],1,'En tydlig kursmapp gör filen enkel att hitta, dela och lämna in.'],['Vilket filnamn är tydligast?',['slutlig_nyaste2','dokument','2026-09-03_fysik_laboration-rorelse_v02'],2,'Datum, ämne, innehåll och version gör filen tydlig.'],['Vad är bäst att göra med en fil som läraren har delat i “Delas med mig”?',['Flytta lärarens original till skrivbordet','Lägg till en genväg i din kursmapp','Ta bort filen direkt'],1,'En genväg hjälper dig organisera filen utan att ändra originalets plats.'],['Vilken behörighet väljer du för en klasskamrat som ska ge respons men inte ändra texten?',['Läsbehörig','Kommentator','Redigerare'],1,'Kommentator kan lämna kommentarer utan att ändra innehållet.'],['Vad gör ⌘ Z?',['Sparar','Ångrar senaste åtgärden','Stänger fönstret'],1,'⌘ Z ångrar senaste åtgärden.'],['Vad gör Skift-⌘ N i Finder?',['Skapar en ny mapp','Öppnar en ny webbläsarflik','Tar skärmbild'],0,'Skift-⌘ N skapar en ny mapp i Finder.'],['Vilket är klokt före en inlämning?',['Kontrollera filnamn, delning och att filen öppnas','Dela länken offentligt med alla','Byta namn till “slutlig”'],0,'Kontroll minskar risken att fel version eller fel behörighet lämnas in.'],['Vad är en varningssignal för nätfiske?',['Ett oväntat meddelande som kräver snabb inloggning','En vanlig Drive-fil från din lärare','En fil som du själv sparade'],0,'Brådska och oväntade inloggningslänkar är vanliga varningssignaler.']];
digitaltChapter.goals.push('använda Chrome för att söka, hantera flikar och spara bokmärken för skolarbetet');
digitaltChapter.sections[0] = ['1. Börja med en struktur som håller','<p>Skapa kursmappar direkt i <strong>huvudmappen i Google Drive</strong>. Lägg inte viktiga filer löst på skrivbordet eller bara i Hämtade filer.</p><p><strong>Förslag i Drive:</strong></p><ul><li>Matematik → Kapitel_01 och Prov_och_repetition</li><li>Fysik → Laborationer och Presentationer</li><li>Kemi</li><li>Teknik</li><li>Gemensamt</li></ul><p>På själva Macen skapar du motsvarande mappar i <strong>Dokument</strong>, inte på skrivbordet. Skapa inte fler mappnivåer än du behöver.</p>'];
digitaltChapter.sections[1] = ['2. Finder på macOS: hitta, skapa och flytta','<p><strong>Finder</strong> är platsen där du hanterar filer på Mac. Öppna Finder via ikonen i Dock. För skolarbete: öppna först <strong>Dokument</strong> i sidofältet och skapa kursmappar där. Låt Skrivbord och Hämtade filer vara tillfälliga platser, inte arkiv.</p><ol><li>Öppna <strong>Dokument</strong> i Finder.</li><li>Skapa en kursmapp med <strong>Skift-⌘-N</strong> eller Arkiv → Ny mapp.</li><li>Ge mappen ett tydligt namn direkt.</li><li>Dra filen till rätt mapp eller använd klipp ut och klistra in.</li><li>Kontrollera att filen verkligen hamnade där.</li></ol><p><strong>Veckorutin:</strong> flytta nya skolfiler från Hämtade filer till rätt kursmapp samma dag.</p>'];
digitaltChapter.sections[3] = ['4. Google Drive: Min enhet, Delas med mig och genvägar','<p><strong>Min enhet</strong> är din egen organiserade yta. Skapa kursmappar direkt där med Ny → Ny mapp: Matematik, Fysik, Kemi, Teknik och Gemensamt. Skapa sedan bara de undermappar som verkligen behövs, exempelvis Fysik → Laborationer och Presentationer.</p><p><strong>Delas med mig</strong> visar material andra har delat med dig. Flytta normalt inte lärarens eller klassens original. Lägg i stället till en <strong>genväg</strong> i rätt kursmapp: högerklicka → Ordna → Lägg till genväg. Då hittar du materialet utan att ändra dess plats.</p><p>Om skolan använder delade enheter följer filer och mappar organisationens regler. Fråga läraren innan du flyttar gemensamt material.</p>'];
digitaltChapter.sections.splice(7, 0, ['8. Chrome: arbeta smart i webbläsaren','<p>Chrome är en arbetsyta, inte bara en plats för sökningar. Håll isär skolarbete och annat genom att använda flikar medvetet och stänga sådant du inte behöver.</p><p><strong>Bokmärken:</strong> Öppna sidan du vill spara och tryck <strong>⌘ D</strong>, eller klicka på stjärnan i adressfältet. Spara den i en bokmärkesmapp, exempelvis <em>Kurser</em> → Matematik, Fysik eller Verktyg. Visa eller dölj bokmärkesfältet med <strong>Skift-⌘ B</strong>. I Bokmärkeshanteraren kan du skapa mappar, byta namn och ta bort gamla länkar.</p><p><strong>Flikar och sökning:</strong> ⌘ L markerar adressfältet så att du kan skriva en webbadress eller söka direkt. ⌘ T öppnar en ny flik, ⌘ W stänger aktuell flik, ⌘ Skift T öppnar den senast stängda fliken och ⌘ 1–8 går till en viss flik från vänster. Använd ⌘ F för att hitta ett ord på en lång sida.</p><p><strong>Arbetsrutin:</strong> öppna endast de källor du använder, spara bra återkommande sidor som bokmärken och skriv ner varifrån viktiga fakta kommer. Logga ut från skolkontot om du använder en gemensam dator. <a href="https://support.google.com/chrome/answer/96816?hl=sv" target="_blank" rel="noopener">Googles Chrome-hjälp om bokmärken</a>.</p>']);
const practiceIndex = digitaltChapter.sections.findIndex(([heading]) => heading === 'Praktisk startuppgift');
digitaltChapter.sections[practiceIndex] = ['Praktisk startuppgift','<ol><li>Skapa mapparna <strong>Matematik, Fysik, Kemi, Teknik och Gemensamt</strong> direkt i huvudmappen i Drive.</li><li>Skapa undermapparna <strong>Laborationer</strong> och <strong>Presentationer</strong> i Fysik.</li><li>Skapa samma kursmappar i <strong>Dokument</strong> på Macen.</li><li>Skapa ett dokument i Fysik/Laborationer och döp det till <code>2026-08-24_fysik_laboration-test_v01</code>. Byt sedan till version <code>v02</code>.</li><li>Lägg till en genväg till en fil från Delas med mig i rätt kursmapp.</li><li>Skapa en bokmärkesmapp i Chrome och spara minst tre användbara skolsidor.</li><li>Öva ⌘ C, ⌘ V, ⌘ Z, ⌘ F, ⌘ L, ⌘ D och Skift-⌘ N.</li><li>Dela dokumentet med en klasskamrat som <strong>Kommentator</strong> och exportera sedan en PDF.</li></ol><p><strong>Metakognition:</strong> Vad tog längst tid? Vilken mapp-, Chrome- eller kortkommandorutin vill du använda nästa gång?</p>'];
digitaltChapter.example = 'Du laddar ned en laborationsmall. Flytta den från Hämtade filer till Dokument/Fysik/Laborationer på Macen, eller till Fysik/Laborationer direkt i Drive. Döp den till 2026-08-24_fysik_laboration-rorelse_v01. Om läraren delade mallen via Drive: skapa en genväg till originalet, eller gör en egen kopia om läraren har bett om det.';
digitaltChapter.quiz.push(['Vilket kortkommando skapar ett bokmärke i Chrome?',['⌘ D','⌘ L','⌘ T'],0,'⌘ D sparar den öppna sidan som bokmärke.'],['Var skapar du kursmappar på själva Macen?',['På skrivbordet','I Dokument','I Papperskorgen'],1,'Dokument är en lämplig och tydlig plats för dina egna kursmappar på Macen.']);
const lgr22 = 'https://www.skolverket.se/undervisning/grundskolan/laroplan-lgr22-for-grundskolan-samt-for-forskoleklassen-och-fritidshemmet/curriculums/LGR22/';
const curriculumNotes = {
  studieteknik: `<p>Det här kapitlet hjälper dig att ta ansvar för ditt lärande i alla ämnen. Grundskolans läroplan lyfter att elever ska få utveckla förmåga att ta ansvar, arbeta självständigt och använda olika arbetssätt. <a href="https://www.skolverket.se/undervisning/grundskolan/laroplan-och-kursplaner-for-grundskolan/laroplan-lgr22-for-grundskolan-samt-for-forskoleklassen-och-fritidshemmet" target="_blank" rel="noopener">Lgr22 – grundskolans läroplan</a>.</p>`,
  digitalt: `<p>Digital kompetens och tekniska lösningar är en del av grundskolans uppdrag. Här repeterar vi praktiska arbetssätt som gör det lättare att arbeta med digitala verktyg, information och dokumentation på teknikprogrammet. <a href="${lgr22}GRGRTEK01?hasSubjects=true&schoolType=GR&tosHeading=Kursplaner&v=5" target="_blank" rel="noopener">Kursplan i teknik, Lgr22</a>.</p>`,
  'matte-tal': `<p>Tal, procent, enheter och rimlighetsbedömning ingår i centralt innehåll i matematik från grundskolan. De behövs sedan när du räknar och tolkar resultat i teknik, fysik och kemi. <a href="${lgr22}GRGRMAT01?hasSubjects=true&schoolType=GR&tosHeading=Kursplaner&v=5" target="_blank" rel="noopener">Kursplan i matematik, Lgr22</a>.</p>`,
  'matte-algebra': `<p>Algebraiska uttryck, ekvationer och formler är centralt innehåll i grundskolans matematik. Därför repeterar vi att tolka, använda och omforma formler före gymnasiets teknik- och naturvetenskapliga kurser. <a href="${lgr22}GRGRMAT01?hasSubjects=true&schoolType=GR&tosHeading=Kursplaner&v=5" target="_blank" rel="noopener">Kursplan i matematik, Lgr22</a>.</p>`,
  'matte-grafer': `<p>Grafer, koordinatsystem, samband, geometri och mätning ingår i grundskolans matematik. Repetition gör det lättare att läsa laborationsresultat, rita diagram och arbeta med modeller. <a href="${lgr22}GRGRMAT01?hasSubjects=true&schoolType=GR&tosHeading=Kursplaner&v=5" target="_blank" rel="noopener">Kursplan i matematik, Lgr22</a>.</p>`,
  fysik: `<p>Grundskolans fysik omfattar bland annat kraft och rörelse, energi, elektricitet, ljus och ljud samt att använda fysik för att granska information och kommunicera. Därför är dessa grunden för repetitionskapitlet. <a href="${lgr22}GRGRFYS01?hasSubjects=true&schoolType=GR&tosHeading=Kursplaner&v=5" target="_blank" rel="noopener">Kursplan i fysik, Lgr22</a>.</p>`,
  kemi: `<p>Grundskolans kemi omfattar bland annat partiklar, ämnens egenskaper, kemiska reaktioner, syror och baser samt säkerhet. Det är därför kapitlet fokuserar på de begrepp och arbetssätt som behövs vidare. <a href="${lgr22}GRGRKEM01?hasSubjects=true&schoolType=GR&tosHeading=Kursplaner&v=5" target="_blank" rel="noopener">Kursplan i kemi, Lgr22</a>.</p>`,
  svenska: `<p>Svenska i grundskolan omfattar att läsa och analysera, söka och värdera information samt skriva olika slags texter med språklig struktur. I teknik och naturvetenskap behövs detta för att förstå uppgifter, laborationer, texter och källor. <a href="${lgr22}GRGRSVE01?hasSubjects=true&schoolType=GR&tosHeading=Kursplaner&v=5" target="_blank" rel="noopener">Kursplan i svenska, Lgr22</a>.</p>`
};
chapters.forEach(chapter => { chapter.curriculumNote = curriculumNotes[chapter.id]; });
const pisaUrl = 'https://www.skolverket.se/statistik-och-utvarderingar/internationella-studier/pisa-matematik-naturvetenskap-och-lasforstaelse';
const timssUrl = 'https://www.skolverket.se/sok-publikationer/publikationsserier/rapporter/2024/timss-2023';
const ntUrl = 'https://www.skolverket.se/download/18.6bfaca41169863e6a65c64b/1553967094853/Utv%C3%A4rdering%20av%20gymnasiedelen%20av%20utvecklingsinsatserna%20inom%20NT-satsningen.pdf';
const researchNotes = {
  studieteknik: `<p>Skolverkets mindre utvärdering av NT-satsningen återger att lärare särskilt lyfte studieinsats, studieteknik, språk, matematik och läsförståelse som utmaningar. Det är lärarerfarenheter, inte en rangordning av alla elevers brister. <a href="${ntUrl}" target="_blank" rel="noopener">Skolverkets NT-satsning</a>.</p>`,
  digitalt: `<p>Det finns ingen nationell studie som visar att just nya teknik- eller naturelever har en bestämd digital kunskapslucka. Kapitlet är därför ett praktiskt stöd för att minska onödig belastning och göra skolarbetet lätt att hitta, dela och lämna in.</p>`,
  'matte-tal': `<p>PISA 2022 visar att svenska 15-åringars resultat i matematik försämrades jämfört med 2018. TIMSS 2023 visar samtidigt förbättrade genomsnitt i årskurs 8, men en större spridning där lågpresterande elever inte förbättrades på samma sätt. Därför börjar kapitlet med grunder och ger möjlighet att repetera i egen takt. <a href="${pisaUrl}" target="_blank" rel="noopener">PISA 2022</a> · <a href="${timssUrl}" target="_blank" rel="noopener">TIMSS 2023</a>.</p>`,
  'matte-algebra': `<p>Nationella och internationella resultat beskriver variation i matematikkunskaper, men de rangordnar inte enskilda delområden som algebra för nya teknikelever. Repetition av algebra och formler finns här eftersom den kunskapen används återkommande i fysik, kemi och teknik. <a href="${pisaUrl}" target="_blank" rel="noopener">PISA 2022</a> · <a href="${timssUrl}" target="_blank" rel="noopener">TIMSS 2023</a>.</p>`,
  'matte-grafer': `<p>Resultaten visar en stor variation i matematik, inte en enhetlig brist hos alla elever. Grafer, geometri, enheter och samband repeteras därför med exempel och kort återkallningsträning innan mer sammansatta uppgifter. <a href="${pisaUrl}" target="_blank" rel="noopener">PISA 2022</a> · <a href="${timssUrl}" target="_blank" rel="noopener">TIMSS 2023</a>.</p>`,
  fysik: `<p>TIMSS 2023 visar att svenska elever i årskurs 8 i genomsnitt presterar över OECD- och EU-genomsnittet i naturvetenskap, men också att resultaten varierar mellan elevgrupper. Kapitlet använder därför begrepp, enheter, modeller och stegvisa beräkningar som återkommande stöd. <a href="${timssUrl}" target="_blank" rel="noopener">TIMSS 2023</a> · <a href="${pisaUrl}" target="_blank" rel="noopener">PISA 2022</a>.</p>`,
  kemi: `<p>Naturvetenskapliga resultat ger ingen exakt lista över vad nya teknikelever saknar, men de visar att förkunskaper varierar. Därför repeterar kapitlet centrala begrepp, partikelmodeller, reaktioner, säkerhet och hur man förklarar ett resultat. <a href="${timssUrl}" target="_blank" rel="noopener">TIMSS 2023</a> · <a href="${pisaUrl}" target="_blank" rel="noopener">PISA 2022</a>.</p>`
};
chapters.forEach(chapter => { if (researchNotes[chapter.id]) chapter.sourceNote = researchNotes[chapter.id]; });
const svenskaChapter = chapters.find(chapter => chapter.id === 'svenska');
svenskaChapter.sourceNote += `<p>PISA 2022 visar också en försämring i svenska 15-åringars läsförståelse jämfört med 2018. Det säger inte exakt vad varje elev behöver, men motiverar träning i att läsa uppgifter, tolka information och formulera svar. <a href="${pisaUrl}" target="_blank" rel="noopener">Skolverkets PISA-sammanställning</a>.</p>`;
const gapSupport = {
  studieteknik: ['Övning: bygg en repetitionskedja','<ol><li>Välj en liten sak du behöver kunna i matematik, fysik eller kemi.</li><li>Förklara den utan stöd i två minuter.</li><li>Rätta mot materialet och skriv exakt vad som saknades.</li><li>Gör en ny kort uppgift om två dagar och en blandad uppgift om en vecka.</li></ol><p>Detta gör luckan synlig och ger dig flera försök att täta den.</p>'],
  'matte-tal': ['Täta luckor: räkneflyt och enheter','<p>Gör först tre mycket korta uppgifter: en med negativa tal, en procentuppgift och en enhetsomvandling. Rätta direkt. Om en uppgift blir fel: skriv <strong>vilken regel</strong> som saknades och gör en nästan likadan uppgift direkt efter.</p><p><strong>Nivå 1:</strong> räkna med hela tal. <strong>Nivå 2:</strong> blanda decimaler och procent. <strong>Nivå 3:</strong> välj själv metod och bedöm rimlighet.</p>'],
  'matte-algebra': ['Täta luckor: algebra i små steg','<p>Skriv alltid ett steg per rad. Markera vad som görs på båda leden och kontrollera svaret genom att sätta tillbaka det i ursprungsekvationen. Börja med <code>x + 4 = 11</code>, fortsätt med <code>3x = 18</code> och blanda sedan in formler.</p><p><strong>Återkalla:</strong> Täck över lösningen och förklara varför samma operation måste göras på båda leden.</p>'],
  'matte-grafer': ['Täta luckor: läs innan du räknar','<p>Innan varje graf- eller geometrifråga: skriv rubrik, axlar, enheter och skala. Vid geometri: rita figur, markera givna mått och skriv vilken formel du väljer. Jämför sedan svaret med en rimlig uppskattning.</p>'],
  fysik: ['Täta luckor: begrepp, enhet, modell','<p>Använd samma rutin i varje uppgift: 1) skriv vad begreppen betyder, 2) skriv givna värden med enheter, 3) välj formel eller modell, 4) räkna, 5) förklara om svaret är rimligt. Gör sedan en muntlig förklaring utan att titta.</p>'],
  kemi: ['Täta luckor: se modellen bakom orden','<p>Rita en enkel partikelmodell för varje nytt begrepp eller reaktion. Säg sedan med egna ord vad bilden visar, och skriv slutligen en ämnesspråklig förklaring. Växlingen bild → vardagsspråk → ämnesspråk hjälper dig upptäcka vad du inte kan ännu.</p>'],
  svenska: ['Täta luckor: förstå frågan först','<p>Markera uppgiftsverbet i varje ny uppgift: <strong>beräkna, förklara, jämför, resonera</strong> eller <strong>beskriv</strong>. Skriv därefter en enkel svarsmall innan du börjar: påstående, förklaring, exempel eller belägg, slutsats.</p>']
};
chapters.forEach(chapter => { if (gapSupport[chapter.id]) chapter.sections.push(gapSupport[chapter.id]); });
const el = (selector) => document.querySelector(selector);
svenskaChapter.sourceNote = `<p><strong>Varför arbetar vi med detta?</strong> I Skolverkets utvärdering av NT-satsningen beskrev lärare att motivation, studieinsats och studieteknik var stora utmaningar. De lyfte också ofta språk och matematik som förkunskaper, samt läsförståelse. Rapporten återger lärares erfarenheter i utvärderingen – den rangordnar inte vad alla elever kan minst. <a href="https://www.skolverket.se/download/18.6bfaca41169863e6a65c64b/1553967094853/Utv%C3%A4rdering%20av%20gymnasiedelen%20av%20utvecklingsinsatserna%20inom%20NT-satsningen.pdf" target="_blank" rel="noopener">Läs Skolverkets rapport</a>.</p><p>Stockholms universitets sammanfattning av forskning om språk- och kunskapsutvecklande naturvetenskapsundervisning visar att begreppsrikt och abstrakt språk kan vara svårtillgängligt. Den lyfter värdet av att koppla vardagsspråk till ämnesspråk, använda visuella resurser, samtala om samband och undervisa om hur naturvetenskapliga argument byggs upp. <a href="https://www.su.se/enheter/nationellt-centrum-for-svenska-som-andrasprak/forskning-och-konferenser/rapporter/sprak--och-kunskapsutvecklande-undervisning-i-det-flersprakiga-klassrummet---naturvetenskap" target="_blank" rel="noopener">Läs Stockholms universitets sammanfattning</a>.</p>`;
svenskaChapter.sourceNote += `<p>PISA 2022 visar också en försämring i svenska 15-åringars läsförståelse jämfört med 2018. Det säger inte exakt vad varje elev behöver, men motiverar träning i att läsa uppgifter, tolka information och formulera svar. <a href="${pisaUrl}" target="_blank" rel="noopener">Skolverkets PISA-sammanställning</a>.</p>`;
svenskaChapter.researchExtension = `<article class="lesson-block"><h3>8. Från vardagsspråk till ämnesspråk</h3><div class="lesson-text"><p>Vardagliga ord kan vara en bra start, men i naturvetenskap behöver du sedan göra innebörden mer exakt. “Energin försvinner” kan bli “energin omvandlas till värme och ljud”. “Ström går åt” kan behöva förklaras med elektrisk energi som omvandlas i en krets.</p><p>Arbeta i tre steg: <strong>vardagsord → ämnesord → förklaring med samband</strong>. Använd gärna en bild, pilmodell eller tabell samtidigt som du skriver. Då kopplas ord, modell och idé ihop.</p></div></article><article class="lesson-block"><h3>9. Samtal och naturvetenskapliga argument</h3><div class="lesson-text"><p>Att kunna ett ord räcker inte om du inte kan använda det i ett resonemang. Arbeta gärna två och två: säg först din vardagliga idé, pröva sedan ett ämnesord och bygg till sist en fullständig förklaring tillsammans.</p><p>När du argumenterar: skriv en <strong>tes</strong>, ge <strong>belägg</strong> i form av fakta eller mätvärden och förklara <strong>hur belägget stödjer tesen</strong>. Exempel: “Koppar bör användas i ledaren eftersom koppar har god elektrisk ledningsförmåga. Det minskar resistansen i kabeln.”</p></div></article><article class="lesson-block research-exercises"><h3>Fördjupade övningar: språk som verktyg</h3><div class="lesson-text"><ol><li>Skriv om “energin försvinner” till en naturvetenskapligt mer korrekt mening. Rita en pilmodell som stöd.</li><li>Arbeta två och två: förklara varför ett metallföremål kan rosta. Börja med vardagsord och förbättra sedan förklaringen med minst två ämnesord.</li><li>Skriv en tes om vilket material som passar i en elkabel. Ge ett belägg och förklara sambandet mellan belägget och tesen.</li><li>Läs instruktionen till en enkel laboration. Markera uppgiftsverb, säkerhetsord, material och vad resultatet ska visa.</li><li>Gör en kort repetitionsplan: välj två ämnesord du ska använda i en ny förklaring om två dagar.</li></ol><p><strong>Reflektera:</strong> Hjälpte bild, samtal eller begreppsbank dig mest? Vad väljer du nästa gång?</p></div></article>`;
function escapeHTML(value) { return value.replace(/[&<>'"]/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c])); }
const isChapterPage = () => Boolean(document.body.dataset.chapter);
const chapterPath = c => isChapterPage() ? `chapter-${c.nr}.html` : `chapters/chapter-${c.nr}.html`;
const presentationPath = c => isChapterPage() ? `../presentation.html?chapter=${c.id}` : `presentation.html?chapter=${c.id}`;
const orderedChapters = () => [...chapters].sort((a, b) => Number(a.nr) - Number(b.nr));
function renderNavigation() { el('#chapter-nav').innerHTML = `${orderedChapters().map(c => `<a href="${chapterPath(c)}">${c.nr}. ${c.title.replace(' för teknikelever','').replace(' från grundskolan','')}</a>`).join('')}<span class="nav-label nav-label-support">Stöd</span><a href="${isChapterPage() ? '../ai-stod.html' : 'ai-stod.html'}">AI-stöd · Paubel</a>`; }
function renderChapters() { el('#chapter-grid').innerHTML = orderedChapters().map(c => `<article class="chapter-card"><span class="chapter-number">Kapitel ${c.nr}</span><h3>${c.title}</h3><p>${c.desc}</p><a class="button" href="${chapterPath(c)}">Öppna kapitel</a></article>`).join(''); }
function showChapter(id) {
  const c = chapters.find(chapter => chapter.id === id); if (!c) return;
  el('#lesson-content').innerHTML = `<div class="lesson-header"><div><p class="eyebrow">Kapitel ${c.nr}</p><h2>${c.title}</h2><p>${c.desc}</p></div><a class="button" href="${presentationPath(c)}">Öppna presentation</a></div><div class="lesson-grid"><div><article class="lesson-block"><h3>Efter kapitlet kan du</h3><ul>${c.goals.map(goal => `<li>${goal}</li>`).join('')}</ul></article>${c.sections.map(([heading, body]) => `<article class="lesson-block"><h3>${heading}</h3><div class="lesson-text">${body}</div></article>`).join('')}<article class="lesson-block"><h3>Genomarbetat exempel</h3><p class="worked-example"><strong>Exempel:</strong> ${c.example}</p></article><article class="lesson-block reflection"><h3>Metakognition: stanna upp</h3><p><strong>Före:</strong> Vad kan jag redan? <strong>Under:</strong> Vilket steg är svårt? <strong>Efter:</strong> Vad behöver jag repetera om två dagar?</p></article></div><aside class="lesson-block"><h3>Kapitelquiz</h3><form class="quiz" data-quiz="${c.id}">${c.quiz.map(([q,answers],i) => `<div class="quiz-question"><p>${i+1}. ${q}</p>${answers.map((answer,j) => `<label class="options"><span><input type="radio" name="q${i}" value="${j}"> ${answer}</span></label>`).join('')}</div>`).join('')}<button class="button primary" type="submit">Rätta quizet</button></form><div id="quiz-result" aria-live="polite"></div><p class="presentation-link"><a href="${presentationPath(c)}">Presentation: ${c.title}</a></p></aside></div>`;
  if (c.sourceNote) { el('#lesson-content').querySelector('.lesson-header').insertAdjacentHTML('afterend', `<details class="lesson-block source-note"><summary>Forskning och utgångspunkt</summary><div class="lesson-text">${c.sourceNote}</div></details>`); }
  if (c.curriculumNote) { const insertAfter = c.sourceNote ? el('#lesson-content .source-note') : el('#lesson-content .lesson-header'); insertAfter.insertAdjacentHTML('afterend', `<details class="lesson-block source-note"><summary>Koppling till grundskolans kursplan</summary><div class="lesson-text">${c.curriculumNote}</div></details>`); }
  if (c.researchExtension) { el('#lesson-content').querySelector('.lesson-grid > div').insertAdjacentHTML('beforeend', c.researchExtension); }
  if (!isChapterPage()) location.hash='lesson';
}
function gradeQuiz(form) { const c=chapters.find(chapter=>chapter.id===form.dataset.quiz); const output=el('#quiz-result'); const unanswered=c.quiz.some((_,i)=>!form.querySelector(`input[name="q${i}"]:checked`)); if(unanswered) { output.innerHTML='<p class="quiz-feedback error">Svara på båda frågorna först.</p>'; return; } let score=0; const feedback=[]; c.quiz.forEach(([,,correct,explanation],i)=>{ const right=+form.querySelector(`input[name="q${i}"]:checked`).value===correct; if(right) score++; feedback.push(`<li>${right?'Rätt':'Repetera'}: ${explanation}</li>`); }); localStorage.setItem(`teknik-quiz-${c.id}`,score); output.innerHTML=`<div class="quiz-feedback"><strong>${score} av ${c.quiz.length} rätt.</strong><ul>${feedback.join('')}</ul><p>Planera en kort repetition av detta kapitel om 2–3 dagar.</p></div>`; }
function setupPlan() { const form=el('#plan-form'); const saved=JSON.parse(localStorage.getItem('teknik-plan')||'null'); if(saved) Object.entries(saved).forEach(([key,value])=>form.elements[key].value=value); form.addEventListener('submit',e=>{e.preventDefault(); const plan=Object.fromEntries(new FormData(form)); localStorage.setItem('teknik-plan',JSON.stringify(plan)); const r=el('#plan-result'); r.className='result show'; r.innerHTML=`<strong>Planen är sparad.</strong><br>Du tränar på <em>${escapeHTML(plan.focus)}</em> – ${escapeHTML(plan.when)}. Bevis på lärande: ${escapeHTML(plan.evidence)}.`; }); }

document.addEventListener('DOMContentLoaded',()=>{ renderNavigation(); if (el('#chapter-grid')) { renderChapters(); setupPlan(); } if (document.body.dataset.chapter) showChapter(document.body.dataset.chapter); document.addEventListener('submit',event=>{ if(event.target.matches('.quiz')) { event.preventDefault(); gradeQuiz(event.target); } }); const menu=el('.menu-button'); if (menu) menu.addEventListener('click',()=>{ const sidebar=el('#sidebar'); const open=sidebar.classList.toggle('open'); menu.setAttribute('aria-expanded',open); }); });
